export * from './user.model';

// API Response
export interface ApiResponse<T> {
  success: boolean;
  message: string;
  data: T;
  timestamp: string;
}

// Pagination
export interface Page<T> {
  content: T[];
  totalElements: number;
  totalPages: number;
  size: number;
  number: number;
  first: boolean;
  last: boolean;
  empty: boolean;
}

// Article
export enum ArticleCategory {
  ACTUALITE = 'ACTUALITE',
  COMMUNIQUE = 'COMMUNIQUE',
  EVENEMENT = 'EVENEMENT',
  PROJET = 'PROJET',
  RAPPORT = 'RAPPORT',
  DISCOURS = 'DISCOURS'
}

export enum ArticleStatus {
  DRAFT = 'DRAFT',
  PENDING = 'PENDING',
  PUBLISHED = 'PUBLISHED',
  ARCHIVED = 'ARCHIVED'
}

export interface Article {
  id: number;
  title: string;
  summary: string;
  content: string;
  featuredImage?: string;
  category: ArticleCategory;
  status: ArticleStatus;
  viewCount: number;
  featured: boolean;
  authorName?: string;
  authorId?: number;
  publishedAt?: string;
  createdAt: string;
  updatedAt?: string;
}

// Project
export enum ProjectStatus {
  PLANIFIE = 'PLANIFIE',
  EN_COURS = 'EN_COURS',
  SUSPENDU = 'SUSPENDU',
  TERMINE = 'TERMINE',
  ANNULE = 'ANNULE'
}

export interface Project {
  id: number;
  name: string;
  description: string;
  objectives?: string;
  featuredImage?: string;
  status: ProjectStatus;
  budget?: number;
  progressPercentage: number;
  startDate?: string;
  endDate?: string;
  partner?: string;
  responsibleDepartment?: string;
  managerName?: string;
  managerId?: number;
  createdAt: string;
  updatedAt?: string;
}

// Document
export enum DocumentCategory {
  RAPPORT = 'RAPPORT',
  FORMULAIRE = 'FORMULAIRE',
  GUIDE = 'GUIDE',
  LOI = 'LOI',
  DECRET = 'DECRET',
  ARRETE = 'ARRETE',
  CIRCULAIRE = 'CIRCULAIRE',
  AUTRE = 'AUTRE'
}

export interface Document {
  id: number;
  title: string;
  description?: string;
  fileName: string;
  filePath: string;
  fileUrl?: string;
  fileType?: string;
  fileSize?: number;
  category: DocumentCategory;
  downloadCount: number;
  isPublic: boolean;
  uploadedByName?: string;
  uploadedById?: number;
  createdAt: string;
  updatedAt?: string;
}

// Contact
export enum ContactStatus {
  NON_LU = 'NON_LU',
  LU = 'LU',
  EN_TRAITEMENT = 'EN_TRAITEMENT',
  TRAITE = 'TRAITE',
  ARCHIVE = 'ARCHIVE'
}

export interface Contact {
  id: number;
  name: string;
  email: string;
  phone?: string;
  subject: string;
  message: string;
  status: ContactStatus;
  response?: string;
  respondedByName?: string;
  respondedById?: number;
  respondedAt?: string;
  createdAt: string;
}

// Dashboard Stats
export interface DashboardStats {
  totalUsers: number;
  activeUsers: number;
  totalArticles: number;
  publishedArticles: number;
  totalProjects: number;
  activeProjects: number;
  completedProjects: number;
  totalDocuments: number;
  publicDocuments: number;
  totalContacts: number;
  pendingContacts: number;
  averageProjectProgress: number;
}
